#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000
#define MAX_NAME 100
typedef struct { char name[MAX_NAME]; int num; } Player;
int compare(const void *a, const void *b) { return ((Player*)a)->num - ((Player*)b)->num; }
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        Player players[N];
        for (int i = 0; i < N; i++) {
            scanf("%s %d", players[i].name, &players[i].num);
        }
        qsort(players, N, sizeof(Player), compare);
        int freq[10001] = {0};
        for (int i = 0; i < N; i++) freq[players[i].num]++;
        int found = 0;
        for (int i = 0; i < N; i++) {
            if (freq[players[i].num] == 1) {
                printf("%s\n", players[i].name);
                found = 1;
                break;
            }
        }
        if (!found) printf("Nobody wins.\n");
    }
    return 0;
}

