#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <unordered_map>
using namespace std;
typedef pair<string, int> Player;
bool compare(const Player &a, const Player &b) { return a.second < b.second; }
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T, N;
    cin >> T;
    while (T--) {
        cin >> N;
        vector<Player> players(N);
        for (int i = 0; i < N; i++) {
            cin >> players[i].first >> players[i].second;
        }
        sort(players.begin(), players.end(), compare);
        unordered_map<int, int> freq;
        for (int i = 0; i < N; i++) {
            freq[players[i].second]++;
        }
        bool found = false;
        for (int i = 0; i < N; i++) {
            if (freq[players[i].second] == 1) {
                cout << players[i].first << endl;
                found = true;
                break;
            }
        }
        if (!found) cout << "Nobody wins." << endl;
    }
    return 0;
}

